// Sanitizer function to prevent HTML layout breaking and [object Object]
function escapeHTML(str) {
  if (!str) return "";

  if (typeof str === 'object') {
    try {
      str = JSON.stringify(str);
    } catch (e) {
      str = String(str);
    }
  }

  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

return $input.all().map(item => {
  // 1. Safely extract variables
  const workflowName = item.json.workflow?.name || 'Unknown Workflow';
  const workflow = escapeHTML(workflowName);

  const executionId = escapeHTML(item.json.execution?.id || 'N/A');
  const executionUrl = item.json.execution?.url || '#'; // Keep URL raw for the href link
  const mode = escapeHTML(item.json.execution?.mode || 'N/A');
  const node = escapeHTML(item.json.execution?.lastNodeExecuted || 'Unknown Node');

  // 2. Extract error safely, checking multiple possible paths
  const rawError = item.json.execution?.error?.message ?? item.json.execution?.error ?? 'Unknown system error';
  const error = escapeHTML(rawError);

  const time = new Date().toLocaleString("en-US", {
    timeZone: "Asia/Dubai",
    dateStyle: "long",
    timeStyle: "medium"
  });

  // 3. Build HTML Template
  const body = `<!DOCTYPE html>
