    img { -ms-interpolation-mode: bicubic; border: 0; outline: none; text-decoration: none; }

    /* Dark mode support */
    @media (prefers-color-scheme: dark) {
      .email-wrapper { background-color: #111827 !important; }
      .email-card { background-color: #1F2937 !important; border-color: #374151 !important; }
      .email-text-primary { color: #F9FAFB !important; }
      .email-text-secondary { color: #D1D5DB !important; }
      .email-text-muted { color: #9CA3AF !important; }
      .email-row-alt { background-color: #283040 !important; }
      .email-border { border-color: #374151 !important; }
      .email-footer { color: #6B7280 !important; }
    }

    /* Mobile responsiveness */
    @media screen and (max-width: 600px) {
      .email-container { width: 100% !important; max-width: 100% !important; }
      .email-card { border-radius: 0 !important; border-left: none !important; border-right: none !important; }
      .email-wrapper { padding: 0 !important; }
      .email-header { padding: 28px 20px !important; }
      .email-body { padding: 28px 20px !important; }
      .email-footer-cell { padding: 24px 20px !important; }
      .email-data-table td { padding: 14px 16px !important; font-size: 15px !important; }
      .email-data-label { width: 130px !important; }
      .email-title { font-size: 20px !important; }
      .email-subtitle { font-size: 15px !important; }
      .email-btn { padding: 16px 28px !important; font-size: 16px !important; width: 100% !important; box-sizing: border-box !important; }
      .email-btn-wrapper { padding: 0 !important; }
    }

    /* Apple Mail / iOS fixes */
    @supports (-webkit-touch-callout: none) {
      .email-btn { -webkit-tap-highlight-color: transparent; }
    }
  </style>
</head>

<body style="margin:0; padding:0; background-color:#f3f4f6;">

  <div style="display:none;font-size:1px;color:#f3f4f6;line-height:1px;max-height:0px;max-width:0px;opacity:0;overflow:hidden;">
    Workflow "${workflow}" failed at ${time}. Tap to review the execution details and error logs.
  </div>

  <table role="presentation" class="email-wrapper" cellpadding="0" cellspacing="0" border="0" width="100%" style="background-color:#f3f4f6; margin:0; padding:20px 0;">
    <tr>
      <td align="center" valign="top">

        <table role="presentation" class="email-container" cellpadding="0" cellspacing="0" border="0" width="600" style="max-width:600px; width:100%; border-collapse:collapse;">

          <tr>
            <td align="center" style="padding:24px 0 20px 0;">
              <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;">
                <tr>
                  <td style="text-align:center;">
                    <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:22px; font-weight:700; color:#dc2626; letter-spacing:3px; text-transform:uppercase;">HAVA</span>
                  </td>
                </tr>
                <tr>
                  <td style="text-align:center; padding-top:4px;">
                    <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:11px; font-weight:500; color:#9ca3af; letter-spacing:4px; text-transform:uppercase;">System Monitor</span>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <tr>
            <td class="email-card" style="background-color:#ffffff; border:1px solid #e5e7eb; border-radius:12px; border-top:4px solid #dc2626; overflow:hidden;">

              <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-collapse:collapse;">
                <tr>
                  <td class="email-header" align="center" style="padding:36px 32px 0 32px;">

                    <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; margin:0 auto 16px auto;">
                      <tr>
                        <td align="center" valign="middle" style="width:56px; height:56px; background-color:#fef2f2; border-radius:50%; text-align:center; vertical-align:middle;">
                          <span style="font-size:28px; line-height:56px; display:inline-block;">&#x26A0;</span>
                        </td>
                      </tr>
                    </table>

                    <h1 class="email-title" style="margin:0; font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:22px; font-weight:700; color:#1f2937; letter-spacing:-0.3px; line-height:1.3;">
                      Workflow Execution Failed
                    </h1>
                    <p class="email-subtitle email-text-secondary" style="margin:10px 0 0 0; font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:400; color:#4b5563; line-height:1.5; max-width:420px;">
                      A workflow has failed and requires your immediate attention. Please review the details below.
                    </p>
                  </td>
                </tr>

                <tr>
                  <td style="padding:0 32px;">
                    <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-collapse:collapse;">
                      <tr>
                        <td style="border-top:1px solid #e5e7eb; font-size:0; line-height:0;">&nbsp;</td>
                      </tr>
                    </table>
                  </td>
                </tr>

                <tr>
                  <td class="email-body" style="padding:24px 32px 12px 32px;">
                    <table role="presentation" class="email-data-table" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-collapse:collapse;">

                      <tr>
                        <td class="email-data-label email-row-alt" style="padding:14px 18px; background-color:#f9fafb; border:1px solid #e5e7eb; border-bottom:none; border-radius:8px 8px 0 0; width:160px;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Workflow</span>
                        </td>
                        <td class="email-row-alt" style="padding:14px 18px; background-color:#f9fafb; border:1px solid #e5e7eb; border-bottom:none; border-left:none; border-radius:0 8px 0 0;">
                          <span class="email-text-primary" style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:600; color:#1f2937;">${workflow}</span>
                        </td>
                      </tr>

                      <tr>
                        <td class="email-data-label" style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; border-bottom:none; width:160px;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Execution ID</span>
                        </td>
                        <td style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; border-bottom:none; border-left:none;">
                          <span class="email-text-primary" style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:500; color:#1f2937; font-family:'SF Mono', 'Fira Code', 'Courier New', monospace;">${executionId}</span>
                        </td>
                      </tr>

                      <tr>
                        <td class="email-data-label email-row-alt" style="padding:14px 18px; background-color:#f9fafb; border:1px solid #e5e7eb; border-bottom:none; width:160px;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Mode</span>
                        </td>
                        <td class="email-row-alt" style="padding:14px 18px; background-color:#f9fafb; border:1px solid #e5e7eb; border-bottom:none; border-left:none;">
                          <span class="email-text-primary" style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:500; color:#1f2937;">${mode}</span>
                        </td>
                      </tr>

                      <tr>
                        <td class="email-data-label" style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; border-bottom:none; width:160px;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Failed Node</span>
                        </td>
                        <td style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; border-bottom:none; border-left:none;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:500; color:#dc2626;">${node}</span>
                        </td>
                      </tr>

                      <tr>
                        <td class="email-data-label email-row-alt" style="padding:14px 18px; background-color:#f9fafb; border:1px solid #e5e7eb; border-bottom:none; width:160px; vertical-align:top;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Error</span>
                        </td>
