                        </td>
                      </tr>

                      <tr>
                        <td class="email-data-label" style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; width:160px; border-radius:0 0 0 8px;">
                          <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#6b7280; text-transform:uppercase; letter-spacing:0.5px;">Timestamp</span>
                        </td>
                        <td style="padding:14px 18px; background-color:#ffffff; border:1px solid #e5e7eb; border-left:none; border-radius:0 0 8px 0;">
                          <span class="email-text-primary" style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:500; color:#1f2937;">${time}</span>
                        </td>
                      </tr>

                    </table>
                  </td>
                </tr>

                <tr>
                  <td class="email-btn-wrapper" style="padding:8px 32px 36px 32px;">
                    <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-collapse:collapse;">
                      <tr>
                        <td align="center">
                          <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; margin:0 auto;">
                            <tr>
                              <td align="center" style="border-radius:8px; background-color:#dc2626;" bgcolor="#dc2626">
                                <a href="${executionUrl}" class="email-btn" target="_blank" style="display:inline-block; padding:16px 36px; font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:15px; font-weight:600; color:#ffffff; text-decoration:none; border-radius:8px; letter-spacing:0.3px; min-width:200px; text-align:center;">
                                  Open Execution &rarr;
                                </a>
                              </td>
                            </tr>
                          </table>
                        </td>
                      </tr>
                    </table>
                  </td>
                </tr>

              </table>
            </td>
          </tr>

          <tr>
            <td class="email-footer-cell" align="center" style="padding:24px 20px 32px 20px;">
              <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;">
                <tr>
                  <td style="text-align:center;">
                    <span style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:13px; font-weight:600; color:#9ca3af; letter-spacing:2px; text-transform:uppercase;">HAVA</span>
                  </td>
                </tr>
                <tr>
                  <td style="text-align:center; padding-top:8px;">
                    <span class="email-footer" style="font-family:'Segoe UI', system-ui, -apple-system, Arial, sans-serif; font-size:12px; font-weight:400; color:#9ca3af; line-height:1.5;">
                      This alert was generated automatically by the n8n Global Error Monitor.<br>
                      You are receiving this because you are configured as a workflow administrator.
                    </span>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

        </table>
        </td>
    </tr>
  </table>

</body>
</html>`;

  return {
    json: {
      subject: `[HAVA] Workflow Failed — ${workflowName}`,
      body
    }
  };
});
